/**
 * tok-cli.config.ts 에서 설정된 instance 경로의 axios instace 가 적용된, api 의 instance 입니다.
 */
export const roomReservationApi = new RoomReservationApi({
  customFetch: fetchExtended,
})

/**
 * query key 에 undefined 를 포함시키지 않기 위한 함수입니다.
 */
const isDefined = (v: unknown) => typeof v !== 'undefined'

/**
 * query-keys
 */
export const QUERY_KEY_ROOM_RESERVATION_API = {
  LIST: (
    variables?: Parameter<typeof roomReservationApi.roomReservationList>,
  ) => ['ROOM_RESERVATION_LIST', variables].filter(isDefined),
  LIST_INFINITE: (
    variables?: Parameter<typeof roomReservationApi.roomReservationList>,
  ) => ['ROOM_RESERVATION_LIST_INFINITE', variables].filter(isDefined),
  CREATE: () => ['ROOM_RESERVATION_CREATE'],
  RETRIEVE: (
    variables?: Parameter<typeof roomReservationApi.roomReservationRetrieve>,
  ) => ['ROOM_RESERVATION_RETRIEVE', variables].filter(isDefined),
  UPDATE: () => ['ROOM_RESERVATION_UPDATE'],
  DESTROY: () => ['ROOM_RESERVATION_DESTROY'],
}

/**
 * No description
 *
 * @tags room_reservation
 * @name RoomReservationList
 * @summary 교리실 예약 목록 조회
 * @request GET:/v1/room_reservation/
 * @secure    */

export const useRoomReservationListQuery = <
  TData = RequestFnReturn<typeof roomReservationApi.roomReservationList>,
>(
  params?: QueryHookParams<
    typeof roomReservationApi.roomReservationList,
    { error: CommonErrorType },
    TData
  >,
) => {
  const queryKey = QUERY_KEY_ROOM_RESERVATION_API.LIST(params?.variables)
  return useQuery({
    queryKey,
    queryFn: () => roomReservationApi.roomReservationList(params?.variables),
    ...params?.options,
  })
}

/**
 * No description    *      * @tags room_reservation
 * @name RoomReservationList
 * @summary 교리실 예약 목록 조회
 * @request GET:/v1/room_reservation/
 * @secure    */
export const useRoomReservationListInfiniteQuery = <
  TData = InfiniteData<
    RequestFnReturn<typeof roomReservationApi.roomReservationList>,
    Parameter<typeof roomReservationApi.roomReservationList>
  >,
>(
  params?: InfiniteQueryHookParams<
    typeof roomReservationApi.roomReservationList,
    CommonErrorType,
    TData
  >,
) => {
  const queryKey = QUERY_KEY_ROOM_RESERVATION_API.LIST_INFINITE(
    params?.variables,
  )
  return useInfiniteQuery({
    queryKey,
    initialPageParam: null,
    queryFn: ({ pageParam }) => {
      const offset = pageParam ?? params?.variables?.query?.offset ?? 0
      return roomReservationApi.roomReservationList({
        ...params?.variables,
        query: { ...params?.variables?.query, offset },
      })
    },
    getNextPageParam: (lastPage, allPages) => {
      if (!lastPage?.isNext) return null
      const fetchedLength = allPages?.length || 0
      const initialOffset = params?.variables?.query?.offset || 0
      const limit = params?.variables?.query?.limit || 0

      return initialOffset + fetchedLength * limit
    },
    ...params?.options,
  })
}

